fn bubble_sort(xs: &mut Vec<i64>) -> i64 {
    let n: i64 = xs.len() as i64;
    let mut swaps: i64 = 0;
    let mut i: i64 = 0;
    while i < n {
        let mut j: i64 = 0;
        while j < ((n).wrapping_sub(i)).wrapping_sub(1) {
            if xs[(j) as usize] > xs[((j).wrapping_add(1)) as usize] {
                let tmp: i64 = xs[(j) as usize];
                xs[(j) as usize] = xs[((j).wrapping_add(1)) as usize];
                xs[((j).wrapping_add(1)) as usize] = tmp;
                swaps = (swaps).wrapping_add(1);
            }
            j = (j).wrapping_add(1);
        }
        i = (i).wrapping_add(1);
    }
    return swaps;
}

fn main() {
    let mut xs: Vec<i64> = vec![5, 3, 8, 1, 4];
    println!("{}", bubble_sort(&mut xs));
}
